// Novel (hand-written) command — not regenerated by the press.
//
// `relations` wraps the existing endpoint commands
// `projects work-items list-relations` and `projects work-items create-relation`
// with friendlier ergonomics, and adds `unset`. The Plane CE REST API does not
// expose DELETE on /work-items/{id}/relations/ (verified 2026-05-12: OPTIONS
// returns Allow: GET, POST). For unset we shell out to a user-configured command
// that drops into the Django shell on your self-hosted Plane API container and
// calls IssueRelation.objects.filter(...).delete(). There is no default: set
// PLANE_RELATION_DELETE_SHELL (or --shell-cmd) to your container's shell access,
// e.g. `ssh <host> docker exec -i <plane-api-container> python manage.py shell`.

package cli

import (
	"encoding/json"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strings"

	"github.com/spf13/cobra"
)

const (
	// PATCH(slug-env-align): the generated client resolves the workspace {slug}
	// from PLANE_SLUG (internal/client/url.go) into Config.TemplateVars. The novel
	// commands source the slug from the same env var so a single PLANE_SLUG drives
	// both generated sync and these hand-written commands (was PLANE_WORKSPACE_SLUG
	// on the pre-reprint CLI). See .printing-press-patches/.
	envWorkspaceSlug    = "PLANE_SLUG"
	envRelationShellCmd = "PLANE_RELATION_DELETE_SHELL"
	// deleteShellExample appears in help and error text only — there is no
	// executable default, since the correct command is specific to each
	// self-hosted Plane deployment. Words are passed unquoted so Windows
	// OpenSSH doesn't single-quote the remote command and break word-splitting.
	deleteShellExample = `ssh <host> docker exec -i <plane-api-container> python manage.py shell`
)

var validRelationTypes = map[string]bool{
	"blocking":      true,
	"blocked_by":    true,
	"duplicate":     true,
	"relates_to":    true,
	"start_after":   true,
	"start_before":  true,
	"finish_after":  true,
	"finish_before": true,
}

func newRelationsCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "relations",
		Short: "List, create, and delete work-item relations (blocking, blocked_by, duplicate, relates_to, temporal).",
		Long: `Manage relationships between Plane work items.

REST in Plane CE v1.3.0 supports listing and creating relations but not deletion;
'unset' shells out to a Django ORM call on your self-hosted Plane API container.
There is no default — configure the shell via PLANE_RELATION_DELETE_SHELL or
--shell-cmd (Plane Cloud has no container shell, so 'unset' is self-hosted only).

Workspace slug defaults to $PLANE_SLUG; project must be specified
explicitly with --project <uuid>.`,
	}
	cmd.AddCommand(newRelationsListCmd(flags))
	cmd.AddCommand(newRelationsSetCmd(flags))
	cmd.AddCommand(newRelationsUnsetCmd(flags))
	return cmd
}

func newRelationsListCmd(flags *rootFlags) *cobra.Command {
	var slug, projectID string

	cmd := &cobra.Command{
		Use:   "list <issue_uuid>",
		Short: "List all relations for a work item, grouped by relation type.",
		Example: `  plane-pp-cli relations list a1d8592d-7cfc-42a2-adc5-3da1f32b3fb5 \
    --project 6ff068e6-c73a-4a5e-923d-90b7dae1daac`,
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) < 1 {
				return usageErr(fmt.Errorf("issue_uuid is required\nUsage: %s <issue_uuid>", cmd.CommandPath()))
			}
			slug = effectiveSlug(flags, slug)
			if slug == "" || slug == "my-workspace" {
				return usageErr(fmt.Errorf("workspace not set: pass --workspace <slug>, --slug <slug>, export %s, or run 'plane-pp-cli workspaces use <slug>'", envWorkspaceSlug))
			}
			if projectID == "" {
				return usageErr(fmt.Errorf("--project is required (Plane API needs project_id in the path)"))
			}
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			applyClientSlug(c, slug)
			// PATCH(slug-env-align): workspace-relative path; BaseURL + TemplateVars[slug] supply /api/v1/workspaces/{slug}.
			path := fmt.Sprintf(
				"/projects/%s/work-items/%s/relations/",
				projectID, args[0],
			)
			data, err := c.Get(cmd.Context(), path, nil)
			if err != nil {
				return classifyAPIError(err, flags)
			}
			return printOutputWithFlags(cmd.OutOrStdout(), data, flags)
		},
	}
	cmd.Flags().StringVar(&slug, "slug", "", "Workspace slug; overridden by the global --workspace (defaults to $"+envWorkspaceSlug+")")
	cmd.Flags().StringVar(&projectID, "project", "", "Project UUID (required)")
	return cmd
}

func newRelationsSetCmd(flags *rootFlags) *cobra.Command {
	var slug, projectID, relType string
	var related []string

	cmd := &cobra.Command{
		Use:   "set <issue_uuid>",
		Short: "Create a relation from <issue_uuid> to one or more related work items.",
		Long: `Create a relation. The Plane API stores the inverse automatically:
'A blocked_by B' creates 'B blocking A' on the other side.

Idempotent — re-running the same set is a no-op at the DB level (get_or_create).`,
		Example: `  # DSO-16 blocked by DSO-15
  plane-pp-cli relations set a1d8592d-7cfc-42a2-adc5-3da1f32b3fb5 \
    --project 6ff068e6-c73a-4a5e-923d-90b7dae1daac \
    --type blocked_by \
    --related 3daf60e5-2083-40a1-87f2-dc4583b15237

  # Multiple blockers in one call
  plane-pp-cli relations set <issue> --project <p> --type blocked_by \
    --related <uuid1> --related <uuid2>`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) < 1 {
				return usageErr(fmt.Errorf("issue_uuid is required\nUsage: %s <issue_uuid>", cmd.CommandPath()))
			}
			slug = effectiveSlug(flags, slug)
			if slug == "" || slug == "my-workspace" {
				return usageErr(fmt.Errorf("workspace not set: pass --workspace <slug>, --slug <slug>, export %s, or run 'plane-pp-cli workspaces use <slug>'", envWorkspaceSlug))
			}
			if projectID == "" {
				return usageErr(fmt.Errorf("--project is required"))
			}
			if !validRelationTypes[relType] {
				return usageErr(fmt.Errorf("--type must be one of: blocking, blocked_by, duplicate, relates_to, start_after, start_before, finish_after, finish_before"))
			}
			if len(related) == 0 {
				return usageErr(fmt.Errorf("--related is required (may be passed multiple times)"))
			}
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			applyClientSlug(c, slug)
			// PATCH(slug-env-align): workspace-relative path; BaseURL + TemplateVars[slug] supply /api/v1/workspaces/{slug}.
			path := fmt.Sprintf(
				"/projects/%s/work-items/%s/relations/",
				projectID, args[0],
			)
			body := map[string]any{
				"issues":        related,
				"relation_type": relType,
			}
			data, _, err := c.Post(cmd.Context(), path, body)
			if err != nil {
				return classifyAPIError(err, flags)
			}
			return printOutputWithFlags(cmd.OutOrStdout(), data, flags)
		},
	}
	cmd.Flags().StringVar(&slug, "slug", "", "Workspace slug; overridden by the global --workspace (defaults to $"+envWorkspaceSlug+")")
	cmd.Flags().StringVar(&projectID, "project", "", "Project UUID (required)")
	cmd.Flags().StringVar(&relType, "type", "", "Relation type (required): blocking | blocked_by | duplicate | relates_to | start_after | start_before | finish_after | finish_before")
	cmd.Flags().StringSliceVar(&related, "related", nil, "UUID of related work item (repeatable)")
	return cmd
}

func newRelationsUnsetCmd(flags *rootFlags) *cobra.Command {
	var slug, projectID, relType, related, shellCmd string

	cmd := &cobra.Command{
		Use:   "unset <issue_uuid>",
		Short: "Delete a relation by shelling out to Django ORM on the API container.",
		Long: `Plane CE v1.3.0 does not expose DELETE on the /relations/ endpoint
(verified by OPTIONS: Allow: GET, POST). To remove a relation this command shells
out to a configurable command that opens a Django shell on the API container and
runs IssueRelation.objects.filter(...).delete().

Configure the shell via PLANE_RELATION_DELETE_SHELL or --shell-cmd. There is no
default; a working value looks like:
  ` + deleteShellExample + `

The command must accept a Python script on stdin and run it inside the Plane
API container's manage.py shell, so this only works against a self-hosted Plane
deployment you can reach (Plane Cloud has no container shell).`,
		Example: `  plane-pp-cli relations unset a1d8592d-7cfc-42a2-adc5-3da1f32b3fb5 \
    --project 6ff068e6-c73a-4a5e-923d-90b7dae1daac \
    --type blocked_by \
    --related 3daf60e5-2083-40a1-87f2-dc4583b15237`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) < 1 {
				return usageErr(fmt.Errorf("issue_uuid is required\nUsage: %s <issue_uuid>", cmd.CommandPath()))
			}
			if projectID == "" {
				return usageErr(fmt.Errorf("--project is required (used as ORM filter sanity check)"))
			}
			if !validRelationTypes[relType] {
				return usageErr(fmt.Errorf("--type must be one of: blocking, blocked_by, duplicate, relates_to, start_after, start_before, finish_after, finish_before"))
			}
			if related == "" {
				return usageErr(fmt.Errorf("--related is required"))
			}
			// Validate UUIDs up front: they are interpolated into a Python script
			// run inside the API container, so reject anything that isn't a
			// canonical UUID rather than relying on the script's quote guard.
			for label, v := range map[string]string{"issue_uuid": args[0], "--related": related, "--project": projectID} {
				if !issueUUIDPattern.MatchString(v) {
					return usageErr(fmt.Errorf("%s must be a UUID, got %q", label, v))
				}
			}
			if shellCmd == "" {
				shellCmd = os.Getenv(envRelationShellCmd)
			}
			if shellCmd == "" {
				return usageErr(fmt.Errorf("no delete shell configured: Plane's REST API has no DELETE for relations, so 'unset' must run a Django-ORM delete inside your self-hosted Plane API container. Set --shell-cmd or %s, e.g. %q", envRelationShellCmd, deleteShellExample))
			}

			script := buildRelationDeleteScript(args[0], related, relType, projectID)

			if flags.dryRun {
				fmt.Fprintf(cmd.OutOrStdout(), "shell: %s\n--- stdin ---\n%s---\n(dry run - not executed)\n", shellCmd, script)
				return nil
			}

			// Run the configured shell command via the user's shell so quoting
			// inside PLANE_RELATION_DELETE_SHELL (e.g. ssh "docker exec ...")
			// is honored. On Windows we use cmd /C; elsewhere sh -c.
			var c *exec.Cmd
			if isWindows() {
				c = exec.CommandContext(cmd.Context(), "cmd", "/C", shellCmd)
			} else {
				c = exec.CommandContext(cmd.Context(), "sh", "-c", shellCmd)
			}
			c.Stdin = strings.NewReader(script)
			out, err := c.CombinedOutput()
			if err != nil {
				return fmt.Errorf("shell command failed: %w\noutput:\n%s", err, string(out))
			}
			result := map[string]any{
				"issue":         args[0],
				"related":       related,
				"relation_type": relType,
				"project":       projectID,
				"output":        strings.TrimSpace(string(out)),
			}
			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return json.NewEncoder(cmd.OutOrStdout()).Encode(result)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "deleted %s -%s-> %s\n%s\n", args[0], relType, related, strings.TrimSpace(string(out)))
			return nil
		},
	}
	cmd.Flags().StringVar(&slug, "slug", "", "Workspace slug (unused for the ORM call but kept for symmetry with set/list)")
	cmd.Flags().StringVar(&projectID, "project", "", "Project UUID (required)")
	cmd.Flags().StringVar(&relType, "type", "", "Relation type (required): blocking | blocked_by | duplicate | relates_to | start_after | start_before | finish_after | finish_before")
	cmd.Flags().StringVar(&related, "related", "", "UUID of related work item (required)")
	cmd.Flags().StringVar(&shellCmd, "shell-cmd", "", "Override $"+envRelationShellCmd+"; must accept a Python script on stdin and run it in Plane's Django shell")
	return cmd
}

func isWindows() bool {
	return runtime.GOOS == "windows"
}

// buildRelationDeleteScript emits a Python snippet for `manage.py shell` that
// deletes a single IssueRelation row. Inputs are UUIDs and a relation_type
// string; they are interpolated as Python string literals. UUIDs come from
// Plane's own data and are validated downstream by Django's UUIDField, so no
// escaping is needed beyond rejecting embedded quotes.
func buildRelationDeleteScript(issue, related, relType, project string) string {
	for _, v := range []string{issue, related, relType, project} {
		if strings.ContainsAny(v, `'"`) || strings.Contains(v, "\n") {
			return fmt.Sprintf("raise SystemExit('invalid argument: %s')\n", v)
		}
	}
	return fmt.Sprintf(`from plane.db.models import IssueRelation
qs = IssueRelation.objects.filter(
    issue_id='%s',
    related_issue_id='%s',
    relation_type='%s',
    project_id='%s',
)
count = qs.count()
qs.delete()
print(f'deleted {count} row(s)')
`, issue, related, relType, project)
}
